# ─────────────────────────────────────────────────────────────
# 공통 유틸리티
# ─────────────────────────────────────────────────────────────
def make_lagged(X_raw, Vx, Vy, num_lags=NUM_LAGS):
    """num_lags개 과거 bin을 concat → 1D feature vector"""
    Xl, vxl, vyl = [], [], []
    for t in range(num_lags, len(X_raw)):
        Xl.append(X_raw[t - num_lags:t, :].flatten())
        vxl.append(Vx[t])
        vyl.append(Vy[t])
    return np.array(Xl), np.array(vxl), np.array(vyl)


def affine_rescale(pred, true):
    """
    Affine rescaling: a * pred + b  to match true's mean & std
    Scale bias 교정용. 논문에서 L2 regularization의 regression-to-mean 제거.
    Returns: rescaled pred, (a, b)
    """
    a = np.std(true) / (np.std(pred) + 1e-8)
    b = np.mean(true) - a * np.mean(pred)
    return a * pred + b, (a, b)


def scale_bias(pred, true):
    """pred σ / true σ  (1.0이 이상적)"""
    return np.std(pred) / (np.std(true) + 1e-8)


def vaf(true, pred):
    """Variance Accounted For = 1 - Var(true-pred)/Var(true)"""
    return 1.0 - np.var(true - pred) / (np.var(true) + 1e-8)


def apply_SER(spike_matrix, ser, rng=None):
    """
    SER 적용: Miss (half_ser) + False Alarm (half_ser)
    spike_matrix: (bins × neurons) int
    """
    if rng is None:
        rng = np.random.default_rng()
    corrupted = spike_matrix.copy().astype(float)
    half = ser / 2.0

    spike_idx = np.argwhere(corrupted > 0)
    zero_idx  = np.argwhere(corrupted == 0)

    if len(spike_idx) > 0 and half > 0:
        n_miss = int(round(len(spike_idx) * half))
        if n_miss > 0:
            ch = rng.choice(len(spike_idx), size=n_miss, replace=False)
            corrupted[spike_idx[ch, 0], spike_idx[ch, 1]] = 0

    if len(zero_idx) > 0 and half > 0:
        n_fa = int(round(int(np.sum(spike_matrix > 0)) * half))
        n_fa = min(n_fa, len(zero_idx))
        if n_fa > 0:
            ch = rng.choice(len(zero_idx), size=n_fa, replace=False)
            corrupted[zero_idx[ch, 0], zero_idx[ch, 1]] = 1

    return corrupted


# ─────────────────────────────────────────────────────────────
# Trial-level KFold 생성기
# Trial 경계를 절대 넘지 않도록 trial 단위로 분할
# ─────────────────────────────────────────────────────────────
def trial_kfold_indices(n_trials, n_folds=N_FOLDS):
    """trial 인덱스 배열을 n_folds로 분할"""
    kf = KFold(n_splits=n_folds, shuffle=False)
    return list(kf.split(np.arange(n_trials)))


def assemble_split(trial_indices, spike_data=None, X_corrupted=None, num_lags=NUM_LAGS):
    """
    trial 인덱스 리스트 → lag feature, Vx, Vy 합산
    spike_data가 None이면 trials_X 전역 변수 사용
    """
    Xl, vxl, vyl = [], [], []
    for ti in trial_indices:
        if X_corrupted is not None:
            start = sum(len(trials_X[j]) for j in range(ti))
            end   = start + len(trials_X[ti])
            x_trial = X_corrupted[start:end]
        else:
            x_trial = trials_X[ti]
        a, b, c = make_lagged(x_trial, trials_Vx[ti], trials_Vy[ti], num_lags)
        Xl.append(a); vxl.append(b); vyl.append(c)
    return np.vstack(Xl), np.concatenate(vxl), np.concatenate(vyl)


# ─────────────────────────────────────────────────────────────
# DECODER 1: Ridge
# ─────────────────────────────────────────────────────────────
class RidgeDecoder:
    def __init__(self, alpha=RIDGE_ALPHA, sigma=GAUSS_SIGMA):
        self.mx = Ridge(alpha=alpha)
        self.my = Ridge(alpha=alpha)
        self.sigma = sigma

    def fit(self, X, vx, vy):
        self.mx.fit(X, vx)
        self.my.fit(X, vy)

    def predict(self, X):
        vxp = gaussian_filter1d(self.mx.predict(X), self.sigma)
        vyp = gaussian_filter1d(self.my.predict(X), self.sigma)
        return vxp, vyp


# ─────────────────────────────────────────────────────────────
# DECODER 2: MLP
# ─────────────────────────────────────────────────────────────
class MLPDecoder:
    def __init__(self, sigma=GAUSS_SIGMA):
        self.mx = MLPRegressor(
            hidden_layer_sizes=(256, 128),
            activation='relu',
            max_iter=300,
            learning_rate_init=1e-3,
            early_stopping=True,
            random_state=42
        )
        self.my = MLPRegressor(
            hidden_layer_sizes=(256, 128),
            activation='relu',
            max_iter=300,
            learning_rate_init=1e-3,
            early_stopping=True,
            random_state=42
        )
        self.scaler = StandardScaler()
        self.sigma  = sigma

    def fit(self, X, vx, vy):
        Xs = self.scaler.fit_transform(X)
        self.mx.fit(Xs, vx)
        self.my.fit(Xs, vy)

    def predict(self, X):
        Xs  = self.scaler.transform(X)
        vxp = gaussian_filter1d(self.mx.predict(Xs), self.sigma)
        vyp = gaussian_filter1d(self.my.predict(Xs), self.sigma)
        return vxp, vyp


# ─────────────────────────────────────────────────────────────
# DECODER 3: LSTM (PyTorch)
# ─────────────────────────────────────────────────────────────
class LSTMNet(nn.Module):
    def __init__(self, input_dim, hidden=128, n_layers=2, dropout=0.2):
        super().__init__()
        self.lstm = nn.LSTM(input_dim, hidden, n_layers,
                            batch_first=True, dropout=dropout)
        self.fc   = nn.Linear(hidden, 2)

    def forward(self, x):
        # x: (batch, seq_len=1, features)  ← 우리는 이미 flattened lag feature
        # reshape to (batch, lag, n_neurons)
        out, _ = self.lstm(x)
        return self.fc(out[:, -1, :])   # last timestep → (batch, 2)


class LSTMDecoder:
    """
    입력: lagged feature (batch, NUM_LAGS * 161)
    reshape → (batch, NUM_LAGS, 161) → LSTM
    """
    def __init__(self, n_neurons=161, num_lags=NUM_LAGS, sigma=GAUSS_SIGMA,
                 epochs=50, lr=5e-4, batch_size=256, clip=1.0):
        self.n_neurons  = n_neurons
        self.num_lags   = num_lags
        self.sigma      = sigma
        self.epochs     = epochs
        self.lr         = lr
        self.batch_size = batch_size
        self.clip       = clip
        self.scaler     = StandardScaler()
        self.model      = None

    def _to_seq(self, X_flat):
        return X_flat.reshape(-1, self.num_lags, self.n_neurons)

    def fit(self, X, vx, vy):
        Xs     = self.scaler.fit_transform(X)
        Xseq   = torch.tensor(self._to_seq(Xs), dtype=torch.float32)
        y_both = torch.tensor(np.stack([vx, vy], axis=1), dtype=torch.float32)
        ds     = TensorDataset(Xseq, y_both)
        dl     = DataLoader(ds, batch_size=self.batch_size, shuffle=True)

        self.model = LSTMNet(self.n_neurons).to(DEVICE)
        opt = optim.Adam(self.model.parameters(), lr=self.lr)
        # cosine annealing scheduler
        scheduler = optim.lr_scheduler.CosineAnnealingLR(opt, T_max=self.epochs)
        loss_fn = nn.MSELoss()

        self.model.train()
        for ep in range(self.epochs):
            for xb, yb in dl:
                xb, yb = xb.to(DEVICE), yb.to(DEVICE)
                opt.zero_grad()
                loss = loss_fn(self.model(xb), yb)
                loss.backward()
                # gradient clipping — LSTM 안정성 핵심
                nn.utils.clip_grad_norm_(self.model.parameters(), self.clip)
                opt.step()
            scheduler.step()

    def predict(self, X):
        Xs   = self.scaler.transform(X)
        Xseq = torch.tensor(self._to_seq(Xs), dtype=torch.float32)
        self.model.eval()
        with torch.no_grad():
            preds = []
            for i in range(0, len(Xseq), 512):
                preds.append(self.model(Xseq[i:i+512].to(DEVICE)).cpu().numpy())
        pred = np.vstack(preds)
        vxp  = gaussian_filter1d(pred[:, 0], self.sigma)
        vyp  = gaussian_filter1d(pred[:, 1], self.sigma)
        return vxp, vyp


# ─────────────────────────────────────────────────────────────
# DECODER 4: Causal Transformer (PyTorch)
# Attention map 추출 버그 수정 버전
# ─────────────────────────────────────────────────────────────
class CausalTransformerNet(nn.Module):
    """
    입력: (batch, seq_len=NUM_LAGS, n_neurons=161)
    Causal self-attention × n_layers
    출력: (batch, 2)  → (vx, vy)

    Attention 추출:
        forward(x, return_attn=True) 시 마지막 레이어의
        마지막 query 위치(t=now) attention weight 반환
    """
    def __init__(self, n_neurons=161, d_model=128, n_heads=4,
                 n_layers=3, dropout=0.1, num_lags=NUM_LAGS):
        super().__init__()
        self.num_lags = num_lags
        self.embed    = nn.Linear(n_neurons, d_model)

        # 각 레이어를 직접 쌓아서 attention weight 접근 가능하게
        self.attn_layers = nn.ModuleList([
            nn.MultiheadAttention(d_model, n_heads,
                                  dropout=dropout, batch_first=True)
            for _ in range(n_layers)
        ])
        self.norms    = nn.ModuleList([nn.LayerNorm(d_model) for _ in range(n_layers)])
        self.ffns     = nn.ModuleList([
            nn.Sequential(
                nn.Linear(d_model, d_model * 4),
                nn.GELU(),
                nn.Dropout(dropout),
                nn.Linear(d_model * 4, d_model),
                nn.Dropout(dropout)
            ) for _ in range(n_layers)
        ])
        self.norm_out = nn.LayerNorm(d_model)
        self.fc       = nn.Linear(d_model, 2)

        # causal mask (상삼각 -inf, 대각선 포함 0)
        # ★ 버그 수정: diagonal=1 → 대각선 자신은 attend 가능
        self.register_buffer(
            'causal_mask',
            torch.triu(torch.ones(num_lags, num_lags) * float('-inf'), diagonal=1)
        )

    def forward(self, x, return_attn=False):
        # x: (batch, seq_len, n_neurons)
        h = self.embed(x)  # (batch, seq_len, d_model)

        attn_weights_all = []
        for attn, norm, ffn in zip(self.attn_layers, self.norms, self.ffns):
            # need_weights=True → 각 레이어 attention weight 저장
            h_attn, w = attn(h, h, h,
                             attn_mask=self.causal_mask,
                             need_weights=True,
                             average_attn_weights=True)  # (batch, seq, seq) 평균
            h = norm(h + h_attn)
            h = h + ffn(h)
            attn_weights_all.append(w)  # (batch, seq_len, seq_len)

        h   = self.norm_out(h)
        out = self.fc(h[:, -1, :])  # last position → (batch, 2)

        if return_attn:
            return out, attn_weights_all  # list of (batch, seq, seq)
        return out


class TransformerDecoder:
    def __init__(self, n_neurons=161, num_lags=NUM_LAGS, sigma=GAUSS_SIGMA,
                 epochs=60, lr=1e-3, batch_size=256, clip=1.0):
        self.n_neurons  = n_neurons
        self.num_lags   = num_lags
        self.sigma      = sigma
        self.epochs     = epochs
        self.lr         = lr
        self.batch_size = batch_size
        self.clip       = clip
        self.scaler     = StandardScaler()
        self.model      = None

    def _to_seq(self, X_flat):
        return X_flat.reshape(-1, self.num_lags, self.n_neurons)

    def fit(self, X, vx, vy):
        Xs     = self.scaler.fit_transform(X)
        Xseq   = torch.tensor(self._to_seq(Xs), dtype=torch.float32)
        y_both = torch.tensor(np.stack([vx, vy], axis=1), dtype=torch.float32)
        ds     = TensorDataset(Xseq, y_both)
        dl     = DataLoader(ds, batch_size=self.batch_size, shuffle=True)

        self.model = CausalTransformerNet(self.n_neurons, num_lags=self.num_lags).to(DEVICE)
        opt       = optim.Adam(self.model.parameters(), lr=self.lr, weight_decay=1e-5)
        scheduler = optim.lr_scheduler.CosineAnnealingLR(opt, T_max=self.epochs)
        loss_fn   = nn.MSELoss()

        self.model.train()
        for ep in range(self.epochs):
            for xb, yb in dl:
                xb, yb = xb.to(DEVICE), yb.to(DEVICE)
                opt.zero_grad()
                loss = loss_fn(self.model(xb), yb)
                loss.backward()
                nn.utils.clip_grad_norm_(self.model.parameters(), self.clip)
                opt.step()
            scheduler.step()

    def predict(self, X):
        Xs   = self.scaler.transform(X)
        Xseq = torch.tensor(self._to_seq(Xs), dtype=torch.float32)
        self.model.eval()
        with torch.no_grad():
            preds = []
            for i in range(0, len(Xseq), 512):
                preds.append(self.model(Xseq[i:i+512].to(DEVICE)).cpu().numpy())
        pred = np.vstack(preds)
        vxp  = gaussian_filter1d(pred[:, 0], self.sigma)
        vyp  = gaussian_filter1d(pred[:, 1], self.sigma)
        return vxp, vyp

    def extract_attention(self, X, n_samples=200):
        """
        ★ 버그 수정: 마지막 query(t=now)의 attention을 과거 key 위치별로 추출
        Returns:
            attn_profile: list of (num_lags,) arrays, 레이어 수만큼
                          index 0 = 가장 먼 과거(-200ms),
                          index -1 = now(0ms)
        """
        Xs   = self.scaler.transform(X[:n_samples])
        Xseq = torch.tensor(self._to_seq(Xs), dtype=torch.float32)

        self.model.eval()
        all_weights = [[] for _ in range(len(self.model.attn_layers))]

        with torch.no_grad():
            for i in range(0, len(Xseq), 64):
                batch = Xseq[i:i+64].to(DEVICE)
                _, ws = self.model(batch, return_attn=True)
                for li, w in enumerate(ws):
                    # w: (batch, seq_len, seq_len)
                    # 마지막 query row = [-1, :]  → (batch, seq_len)
                    last_row = w[:, -1, :].cpu().numpy()  # (batch, num_lags)
                    all_weights[li].append(last_row)

        # 평균
        profiles = []
        for li in range(len(self.model.attn_layers)):
            stacked = np.vstack(all_weights[li])   # (n_samples, num_lags)
            profiles.append(stacked.mean(axis=0))  # (num_lags,)

        return profiles  # 각 레이어별 attention profile


# ─────────────────────────────────────────────────────────────
# PHASE 2: Trial-level CV — 기저 성능 측정
# ─────────────────────────────────────────────────────────────
print("\n" + "="*60)
print("PHASE 2: Trial-level CV Baseline (SER=0)")
print("="*60)

DECODER_NAMES   = ['Ridge', 'MLP', 'LSTM', 'Transformer']
fold_splits     = trial_kfold_indices(n_trials, N_FOLDS)

# 결과 저장 구조
results_base = {name: {'rx': [], 'ry': [], 'vaf_x': [], 'vaf_y': [],
                        'sb_x_raw': [], 'sb_y_raw': [],
                        'sb_x_res': [], 'sb_y_res': [],
                        'preds': None}
                for name in DECODER_NAMES}

# 마지막 fold 예측값 (시각화용)
last_fold_preds = {name: None for name in DECODER_NAMES}

transformer_decoder_ref = None  # attention 추출용

for fold_i, (tr_trials, te_trials) in enumerate(fold_splits):
    print(f"\n── Fold {fold_i+1}/{N_FOLDS} ──")

    Xtr, vxtr, vytr = assemble_split(tr_trials)
    Xte, vxte, vyte = assemble_split(te_trials)

    decoders = {
        'Ridge':       RidgeDecoder(),
        'MLP':         MLPDecoder(),
        'LSTM':        LSTMDecoder(epochs=50),
        'Transformer': TransformerDecoder(epochs=60),
    }

    for name, dec in decoders.items():
        dec.fit(Xtr, vxtr, vytr)
        vxp_raw, vyp_raw = dec.predict(Xte)

        # ── Scale bias BEFORE rescaling ──
        sb_x_raw = scale_bias(vxp_raw, vxte)
        sb_y_raw = scale_bias(vyp_raw, vyte)

        # ── Affine rescaling ──
        vxp, _ = affine_rescale(vxp_raw, vxte)
        vyp, _ = affine_rescale(vyp_raw, vyte)

        # ── Scale bias AFTER rescaling (should be ~1.0) ──
        sb_x_res = scale_bias(vxp, vxte)
        sb_y_res = scale_bias(vyp, vyte)

        rx, _ = pearsonr(vxte, vxp)
        ry, _ = pearsonr(vyte, vyp)
        vx_v  = vaf(vxte, vxp)
        vy_v  = vaf(vyte, vyp)

        results_base[name]['rx'].append(rx)
        results_base[name]['ry'].append(ry)
        results_base[name]['vaf_x'].append(vx_v)
        results_base[name]['vaf_y'].append(vy_v)
        results_base[name]['sb_x_raw'].append(sb_x_raw)
        results_base[name]['sb_y_raw'].append(sb_y_raw)
        results_base[name]['sb_x_res'].append(sb_x_res)
        results_base[name]['sb_y_res'].append(sb_y_res)

        print(f"  {name:12s}  rx={rx:.4f}  ry={ry:.4f}  "
              f"SB_raw={sb_x_raw:.3f}/{sb_y_raw:.3f}  "
              f"SB_res={sb_x_res:.3f}/{sb_y_res:.3f}")

        if fold_i == N_FOLDS - 1:
            last_fold_preds[name] = (vxte, vxp, vyte, vyp)
            if name == 'Transformer':
                transformer_decoder_ref = dec

# r_neural 계산
r_neural = {name: (np.mean(results_base[name]['rx']) +
                   np.mean(results_base[name]['ry'])) / 2
            for name in DECODER_NAMES}

print("\n=== Phase 2 요약 ===")
print(f"{'Decoder':12s}  {'r_neural':>8}  {'vs SNN':>8}  "
      f"{'VAF':>6}  {'SB_raw(x)':>10}  {'SB_res(x)':>10}")
for name in DECODER_NAMES:
    r   = r_neural[name]
    v   = (np.mean(results_base[name]['vaf_x']) +
           np.mean(results_base[name]['vaf_y'])) / 2
    sbr = np.mean(results_base[name]['sb_x_raw'])
    sbs = np.mean(results_base[name]['sb_x_res'])
    print(f"  {name:12s}  {r:>8.4f}  {r-PAPER_R:>+8.4f}  "
          f"{v:>6.3f}  {sbr:>10.3f}  {sbs:>10.3f}")
print(f"  {'Paper SNN':12s}  {PAPER_R:>8.4f}")


# ─────────────────────────────────────────────────────────────
# PHASE 3: SER Sweep
# ── 핵심 설계 원칙: Phase 2 모델 freeze, test set만 corrupt ──
# ─────────────────────────────────────────────────────────────
print("\n" + "="*60)
print("PHASE 3: SER Robustness Sweep")
print("="*60)

n_neurons    = X_all.shape[1]
bin_sparsity = np.mean(X_all > 0)
avg_active   = n_neurons * bin_sparsity
print(f"\n[Noise Averaging Analysis]")
print(f"  N neurons:            {n_neurons}")
print(f"  Active per bin (avg): {avg_active:.1f}")
print(f"  → SER=0.01 → ~{avg_active*0.01:.2f} corrupted channels/bin")
print(f"  → noise dilution ≈ 1/{avg_active:.0f}\n")

# ── Step A: Phase 2의 clean 모델을 fold별로 저장 ──
# trained_folds[fold_i][decoder_name] = {
#     'decoder': dec,           ← freeze된 모델
#     'vxte': vxte_clean,       ← clean test target (기준값 고정)
#     'vyte': vyte_clean,
#     'te_trials': te_trials
# }
print("Phase 2 모델 재훈련 (fold별 저장)...")
trained_folds = {}

for fold_i, (tr_trials, te_trials) in enumerate(fold_splits):
    Xtr, vxtr, vytr = assemble_split(tr_trials)   # clean train
    Xte, vxte, vyte = assemble_split(te_trials)   # clean test

    fold_entry = {}
    for name in DECODER_NAMES:
        dec = {'Ridge':       RidgeDecoder(),
               'MLP':         MLPDecoder(),
               'LSTM':        LSTMDecoder(epochs=50),
               'Transformer': TransformerDecoder(epochs=60)}[name]
        dec.fit(Xtr, vxtr, vytr)   # ← clean data로 1회만 훈련
        fold_entry[name] = {
            'decoder':   dec,
            'vxte':      vxte,      # clean target 고정
            'vyte':      vyte,
            'te_trials': list(te_trials)
        }
        print(f"  Fold {fold_i+1}  {name:12s} trained.")
    trained_folds[fold_i] = fold_entry

# ── Step B: SER sweep — inference only, 재훈련 없음 ──
ser_results = {name: {ser: [] for ser in SER_VALUES} for name in DECODER_NAMES}

# SER=0: Phase 2 r_neural 그대로 (정의상 ratio=1.0)
for name in DECODER_NAMES:
    ser_results[name][0] = [r_neural[name]]

for ser in SER_VALUES[1:]:
    print(f"\n── SER={ser:.0e} ──")
    for rep in range(N_REPEATS):
        rng = np.random.default_rng(seed=rep * 100 + SER_VALUES.index(ser))

        # X 전체에 SER 적용 → trial 단위 분리
        X_corr = apply_SER(X_all, ser, rng=rng)
        idx = 0
        X_corr_trials = []
        for ti in range(n_trials):
            tlen = len(trials_X[ti])
            X_corr_trials.append(X_corr[idx:idx + tlen])
            idx += tlen

        fold_rs = {name: [] for name in DECODER_NAMES}

        for fold_i, fold_entry in trained_folds.items():
            te_trials = fold_entry[list(fold_entry.keys())[0]]['te_trials']

            # ★ test set만 corrupt — train은 건드리지 않음
            Xte_c  = np.vstack([make_lagged(X_corr_trials[ti],
                                            trials_Vx[ti],
                                            trials_Vy[ti])[0]
                                for ti in te_trials])

            for name in DECODER_NAMES:
                info = fold_entry[name]
                dec  = info['decoder']     # freeze된 Phase 2 모델
                vxte = info['vxte']        # clean target (기준 고정)
                vyte = info['vyte']

                # ★ 재훈련 없이 predict만
                vxp_r, vyp_r = dec.predict(Xte_c)
                vxp, _ = affine_rescale(vxp_r, vxte)
                vyp, _ = affine_rescale(vyp_r, vyte)

                rx, _ = pearsonr(vxte, vxp)
                ry, _ = pearsonr(vyte, vyp)
                fold_rs[name].append((rx + ry) / 2)

        for name in DECODER_NAMES:
            r_rep = float(np.mean(fold_rs[name]))
            ser_results[name][ser].append(r_rep)
            print(f"  {name:12s}  rep={rep+1}  r={r_rep:.4f}")

# ── 성능 유지율 계산 ──
ratio_mean = {name: [] for name in DECODER_NAMES}
ratio_std  = {name: [] for name in DECODER_NAMES}
for name in DECODER_NAMES:
    r0 = r_neural[name]   # Phase 2 고정값
    for ser in SER_VALUES:
        vals = ser_results[name][ser]
        ratio_mean[name].append(float(np.mean(vals)) / r0)
        ratio_std[name].append(float(np.std(vals))  / r0
                               if len(vals) > 1 else 0.0)

print("\n=== SER 성능 유지율 ===")
header = f"{'SER':>10}" + "".join(f"  {n:>12}" for n in DECODER_NAMES) + "  Paper"
print(header)
paper_ref = {0: '—', 1e-4: '1.000', 3e-4: '—',
             1e-3: '0.888', 3e-3: '—', 1e-2: '0.700'}
for i, ser in enumerate(SER_VALUES):
    row = f"{ser:>10.0e}"
    for name in DECODER_NAMES:
        row += f"  {ratio_mean[name][i]:>12.4f}"
    row += f"  {paper_ref.get(ser, '—'):>5}"
    print(row)


# ─────────────────────────────────────────────────────────────
# PHASE 4: Transformer Attention Map (버그 수정)
# ─────────────────────────────────────────────────────────────
print("\n" + "="*60)
print("PHASE 4: Transformer Attention Extraction (Fixed)")
print("="*60)

if transformer_decoder_ref is not None:
    # 마지막 fold test set으로 attention 추출
    last_te_trials = fold_splits[-1][1]
    Xte_attn, _, _ = assemble_split(last_te_trials)

    attn_profiles = transformer_decoder_ref.extract_attention(Xte_attn, n_samples=300)
    n_layers = len(attn_profiles)

    # 시간 레이블: -200ms(index 0) ... 0ms(index -1)
    time_ms = np.arange(-NUM_LAGS, 0) * 10  # [-200, -190, ..., -10] ms
    # ★ index -1 = "now" = 0ms 자체 (현재 bin)
    # 수정: time_ms의 마지막이 -10ms → "now=0ms" 포함 위해 +10
    time_ms = time_ms + 10   # [-190ms, ..., 0ms]
    print(f"  추출된 레이어 수: {n_layers}")
    print(f"  Attention at now (last index): "
          + " | ".join(f"L{i+1}={attn_profiles[i][-1]:.4f}" for i in range(n_layers)))
    print(f"  Attention peak lag: "
          + " | ".join(f"L{i+1}={time_ms[np.argmax(attn_profiles[i])]:.0f}ms"
                       for i in range(n_layers)))
else:
    print("  Transformer decoder not available (training skipped)")
    attn_profiles = None
    time_ms = np.arange(-NUM_LAGS, 0) * 10 + 10


