    Xseq_attn = torch.tensor(
        Xs_attn.reshape(-1, NUM_LAGS, 161), dtype=torch.float32
    )

    # 레이어별 full attention matrix (query × key 전체) 추출
    transformer_decoder_ref.model.eval()
    full_attn_maps = [[] for _ in range(n_layers)]
    with torch.no_grad():
        for i in range(0, min(100, len(Xseq_attn)), 64):
            batch = Xseq_attn[i:i+64].to(DEVICE)
            _, ws = transformer_decoder_ref.model(batch, return_attn=True)
            for li, w in enumerate(ws):
                full_attn_maps[li].append(w.cpu().numpy())  # (batch, seq, seq)

    time_labels = [f'{t}ms' for t in time_ms]
    for li in range(n_layers):
        avg_map = np.vstack(full_attn_maps[li]).mean(axis=0)  # (seq, seq)
        ax = axes4[li]
        im = ax.imshow(avg_map, aspect='auto', cmap='hot_r', origin='upper')
        ax.set_xlabel('Key (과거 시간 bin→)')
        ax.set_ylabel('Query (현재 예측 시점)')
        ticks = list(range(0, NUM_LAGS, 4))
