    ax5.axvline(0, color='k', linestyle='--', lw=1, alpha=0.6, label='t = now')
    ax5.set_xlabel('Time relative to prediction (ms)', fontsize=12)
    ax5.set_ylabel('Attention Weight', fontsize=12)
    ax5.set_title('Attention Distribution at Prediction Time (t=now)\n'
                  'Fixed: last query row → correctly shows focus on past bins',
                  fontsize=11, fontweight='bold')
    ax5.legend(); ax5.grid(True, alpha=0.3)

    # 피크 라그 표시
