# -*- coding: utf-8 -*-
"""
crcns_pmd1_improved.py  (v2-lite: Colab compute 절감)

개선 사항:
  1. Extended SER sweep [0, 1e-4, 1e-3, 1e-2, 5e-2, 1e-1, 2e-1]
     → rate-coded decoder breakdown point 탐색
  2. Affine rescaling → velocity tracking amplitude 보정
  3. Neuron subsampling [40, 161] × 2 reps
     → population averaging 메커니즘 시각화

연산량 절감 (v1 대비):
  N_REPEATS      : 3  → 1   (Ridge 결정론적, 3× 절감)
  SER points     : 10 → 7   (중간 포인트 제거)
  N_SUBSET_VALUES: 4  → 2   (양극단만)
  N_SUBSAMPLE_REPS: 5 → 2   (2.5× 절감)
  총 Ridge fit 수: ~345 → ~80  (약 4.3× 절감)
"""

import scipy.io as sio
import numpy as np
import matplotlib.pyplot as plt
import matplotlib.gridspec as gridspec
from sklearn.linear_model import Ridge, LinearRegression
from sklearn.neural_network import MLPRegressor
from sklearn.model_selection import KFold
from scipy.stats import pearsonr
from scipy.ndimage import gaussian_filter1d
import warnings
warnings.filterwarnings('ignore')

# ─────────────────────────────────────────────────────────────
# 0. 설정값
# ─────────────────────────────────────────────────────────────
DATA_PATH   = '/content/drive/MyDrive/data_and_scripts/source_data/processed/MM_S1_processed.mat'
NUM_LAGS    = 20
BURST_POWER = 1.3
RIDGE_ALPHA = 1.0
N_FOLDS     = 5
GAUSS_SIGMA = 3

# ▼ SER 범위 확장 (breakdown point 탐색), 중간 포인트 제거로 연산 절감
# 필요시 3e-4, 3e-3, 3e-2 추가 가능
SER_VALUES  = [0, 1e-4, 1e-3, 1e-2, 5e-2, 1e-1, 2e-1]

# Ridge는 결정론적(동일 데이터 → 동일 결과)이므로 1회로 충분
# SER corruption의 randomness만 capture하면 됨 → 1회도 representative
N_REPEATS   = 1  # (절감: 3→1, 약 3× 연산 절감)

# 논문 기준값 (Nurmikko et al. 2024)
PAPER_R_NEURAL   = 0.9324
PAPER_SER_POINTS = {1e-4: 1.000, 1e-3: 0.888, 1e-2: 0.700}

# ─────────────────────────────────────────────────────────────
# PHASE 1: 데이터 로딩 & 전처리
# ─────────────────────────────────────────────────────────────
print("=" * 60)
print("PHASE 1: 데이터 로딩 & 전처리")
print("=" * 60)

mat  = sio.loadmat(DATA_PATH, struct_as_record=False, squeeze_me=True)
Data = mat['Data']
n_reaches = len(Data.kinematics)
print(f"총 reaches 수: {n_reaches}")

all_spikes, all_vx, all_vy, trial_lengths = [], [], [], []
for i in range(n_reaches):
    kin    = Data.kinematics[i]
    m1     = Data.neural_data_M1[i]
    pmd    = Data.neural_data_PMd[i]
    neural = np.vstack([m1, pmd])
    all_spikes.append(neural.T)
    all_vx.append(kin[:, 2])
    all_vy.append(kin[:, 3])
    trial_lengths.append(neural.shape[1])

X  = np.vstack(all_spikes)
Vx = np.concatenate(all_vx)
Vy = np.concatenate(all_vy)
trial_lengths = np.array(trial_lengths)

print(f"X shape:  {X.shape}")
print(f"Vx shape: {Vx.shape}")

sparsity   = np.mean(X == 0)
mean_fr    = X.mean() / 0.01
print(f"희소율: {sparsity*100:.2f}% | 평균 발화율: {mean_fr:.2f} Hz")

# ─────────────────────────────────────────────────────────────
# 공통 유틸 함수
# ─────────────────────────────────────────────────────────────
def create_lagged_features(X_raw, Y_vx, Y_vy, num_lags=NUM_LAGS):
    X_lag, vx_lag, vy_lag = [], [], []
    for t in range(num_lags, len(X_raw)):
        X_lag.append(X_raw[t - num_lags:t, :].flatten())
        vx_lag.append(Y_vx[t])
        vy_lag.append(Y_vy[t])
    return np.array(X_lag), np.array(vx_lag), np.array(vy_lag)


def apply_dynamic_weighting(X_feat, burst_power=BURST_POWER):
    return np.where(X_feat > 0, np.power(X_feat, burst_power), 0.0)


def apply_SER(spike_matrix, ser, rng=None):
    """
    SER 적용: miss (half_ser) + false alarm (half_ser)
    """
    if rng is None:
        rng = np.random.default_rng()
    if ser == 0:
        return spike_matrix.copy().astype(float)

    corrupted = spike_matrix.copy().astype(float)
    half_ser  = ser / 2.0

    spike_mask = corrupted > 0
    spike_idx  = np.argwhere(spike_mask)
    if len(spike_idx) > 0:
        n_miss = int(round(len(spike_idx) * half_ser))
        if n_miss > 0:
            chosen = rng.choice(len(spike_idx), size=n_miss, replace=False)
            corrupted[spike_idx[chosen, 0], spike_idx[chosen, 1]] = 0

    zero_mask = corrupted == 0
    zero_idx  = np.argwhere(zero_mask)
    if len(zero_idx) > 0:
        n_original_spikes = int(np.sum(spike_matrix > 0))
        n_false = min(int(round(n_original_spikes * half_ser)), len(zero_idx))
        if n_false > 0:
            chosen = rng.choice(len(zero_idx), size=n_false, replace=False)
            corrupted[zero_idx[chosen, 0], zero_idx[chosen, 1]] = 1

    return corrupted


# ▼ 개선 2: affine rescaling 함수
def fit_affine_rescaler(y_pred, y_true):
    """
    train split에서 learned scale bias를 1-D affine으로 보정.
    y_pred_rescaled = a * y_pred + b
    """
    model = LinearRegression().fit(y_pred.reshape(-1, 1), y_true)
    return model.coef_[0], model.intercept_


def apply_affine(y_pred, a, b):
    return a * y_pred + b


# Trial 누적 시작 인덱스 (전역 bin index 변환용)
trial_starts = np.concatenate([[0], np.cumsum(trial_lengths[:-1])])


def assemble_split(trial_indices, X_corrupted=None):
    """
    trial_indices 리스트의 trial들을 모아 lagged feature + velocity 반환.

    핵심: 각 trial 내부에서만 lag 생성 → cross-trial 경계 오염 없음
    X_corrupted: SER 적용된 전체 X (None이면 clean all_spikes 사용)
    """
    Xl, vxl, vyl = [], [], []
    for ti in trial_indices:
        if X_corrupted is not None:
            s = trial_starts[ti]
            e = s + trial_lengths[ti]
            x_trial = X_corrupted[s:e]
        else:
            x_trial = all_spikes[ti]
        feat, vx_t, vy_t = create_lagged_features(x_trial, all_vx[ti], all_vy[ti])
        feat = apply_dynamic_weighting(feat)
        Xl.append(feat)
        vxl.append(vx_t)
        vyl.append(vy_t)
    return np.vstack(Xl), np.concatenate(vxl), np.concatenate(vyl)


def run_ridge_cv(X_corrupted=None):
    """
    Trial-level 5-fold CV for Ridge.
    X_corrupted: SER 적용된 전체 X (None이면 clean data)

    수정 이유:
      - kf.split(X_feat) → bin-level 분할 → data leakage
      - create_lagged_features(X, ...) → cross-trial lag 오염
      두 문제를 assemble_split으로 동시에 해결
    """
    kf = KFold(n_splits=N_FOLDS, shuffle=False)
    r_x_list, r_y_list = [], []
    last_preds = None

    for train_trials, test_trials in kf.split(np.arange(len(all_spikes))):
        # train: clean / test: clean or corrupted
        Xtr, vxtr, vytr = assemble_split(train_trials)
        Xte, vxte, vyte = assemble_split(test_trials, X_corrupted)

        mx = Ridge(alpha=RIDGE_ALPHA).fit(Xtr, vxtr)
        my = Ridge(alpha=RIDGE_ALPHA).fit(Xtr, vytr)

        vxp_raw = gaussian_filter1d(mx.predict(Xte), sigma=GAUSS_SIGMA)
        vyp_raw = gaussian_filter1d(my.predict(Xte), sigma=GAUSS_SIGMA)

        # affine rescaling: train 예측으로 파라미터 fit → test에 적용
        ax, bx = fit_affine_rescaler(
            gaussian_filter1d(mx.predict(Xtr), sigma=GAUSS_SIGMA), vxtr)
        ay, by = fit_affine_rescaler(
            gaussian_filter1d(my.predict(Xtr), sigma=GAUSS_SIGMA), vytr)

        vxp = apply_affine(vxp_raw, ax, bx)
        vyp = apply_affine(vyp_raw, ay, by)

        rx, _ = pearsonr(vxte, vxp)
        ry, _ = pearsonr(vyte, vyp)
        r_x_list.append(rx)
        r_y_list.append(ry)
        last_preds = (vxte, vxp, vyte, vyp, vxp_raw, vyp_raw)

    return r_x_list, r_y_list, last_preds


# ─────────────────────────────────────────────────────────────
# PHASE 2: 기저 성능 측정 (SER=0)
# ─────────────────────────────────────────────────────────────
print("\n" + "=" * 60)
print("PHASE 2: 기저 디코딩 성능 측정")
print("=" * 60)

r_x_folds, r_y_folds, last_base = run_ridge_cv()

r_neural_x = float(np.mean(r_x_folds))
r_neural_y = float(np.mean(r_y_folds))
r_neural   = (r_neural_x + r_neural_y) / 2

print(f"r_neural_x (mean, affine-rescaled): {r_neural_x:.4f}")
print(f"r_neural_y (mean, affine-rescaled): {r_neural_y:.4f}")
print(f"r_neural   (avg):                   {r_neural:.4f}")
print(f"논문 기준 (SNN):                    {PAPER_R_NEURAL}")

# ─────────────────────────────────────────────────────────────
# ▼ 개선 3: Neuron Subsampling Robustness Analysis
#   "왜 rate-coded decoder는 SER에 robust한가?"를 mechanistic하게 증명
# ─────────────────────────────────────────────────────────────
print("\n" + "=" * 60)
print("PHASE 2.5: Neuron Subsampling Analysis (Population Averaging)")
print("=" * 60)

# 절감: [20,40,80,161] → [40,161] (양극단만으로 contrast 충분)
# 절감: 5 reps → 2 reps
N_SUBSET_VALUES  = [40, 161]
SER_FIXED        = 1e-2
N_SUBSAMPLE_REPS = 2  # (절감: 5→2, 약 2.5× 연산 절감)

subsampling_results = {n: [] for n in N_SUBSET_VALUES}

for n_sub in N_SUBSET_VALUES:
    for rep in range(N_SUBSAMPLE_REPS):
        rng = np.random.default_rng(seed=rep * 100)

        # 뉴런 서브샘플링
        neuron_idx = rng.choice(X.shape[1], size=n_sub, replace=False)
        X_sub      = X[:, neuron_idx]

        # 라그 피처 (clean)
        X_sub_clean_lag, Vx_s, Vy_s = create_lagged_features(X_sub, Vx, Vy)
        X_sub_clean_dyn              = apply_dynamic_weighting(X_sub_clean_lag)

        # SER 적용 후 라그 피처 (corrupted)
        X_sub_corr    = apply_SER(X_sub, SER_FIXED, rng=rng)
        X_sub_lag, _, _ = create_lagged_features(X_sub_corr, Vx, Vy)
        X_sub_dyn       = apply_dynamic_weighting(X_sub_lag)

        # CV: clean으로 학습, corrupted input으로 test
        # ▼ 버그 수정: mc2 = mc로 통일 (같은 모델에 noisy input 주는 것이 올바른 평가)
        kf = KFold(n_splits=N_FOLDS, shuffle=False)
        r_clean_list, r_corr_list = [], []
        for tr_idx, te_idx in kf.split(X_sub_clean_lag):
            mc = Ridge(alpha=RIDGE_ALPHA).fit(X_sub_clean_dyn[tr_idx], Vx_s[tr_idx])

            vxp_c = gaussian_filter1d(mc.predict(X_sub_clean_dyn[te_idx]), sigma=GAUSS_SIGMA)
            rc, _ = pearsonr(Vx_s[te_idx], vxp_c)
            r_clean_list.append(rc)

            vxp_n = gaussian_filter1d(mc.predict(X_sub_dyn[te_idx]), sigma=GAUSS_SIGMA)
            rn, _ = pearsonr(Vx_s[te_idx], vxp_n)
            r_corr_list.append(rn)

        ratio = np.mean(r_corr_list) / max(np.mean(r_clean_list), 1e-6)
        subsampling_results[n_sub].append(ratio)
        print(f"  N={n_sub:3d}  rep={rep+1}  ratio={ratio:.4f}")

sub_mean = {n: np.mean(subsampling_results[n]) for n in N_SUBSET_VALUES}
sub_std  = {n: np.std(subsampling_results[n])  for n in N_SUBSET_VALUES}

print("\n=== Subsampling 결과 ===")
print(f"{'N neurons':>12}  {'ρ (ratio)':>10}  {'std':>8}")
for n in N_SUBSET_VALUES:
    print(f"  {n:>10}  {sub_mean[n]:>10.4f}  {sub_std[n]:>8.4f}")

# ─────────────────────────────────────────────────────────────
# PHASE 3: SER 시뮬레이션 & 성능 측정 (Extended)
# ─────────────────────────────────────────────────────────────
print("\n" + "=" * 60)
print("PHASE 3: Extended SER Robustness Sweep")
print("=" * 60)

results_ser = {ser: [] for ser in SER_VALUES}

for ser_idx, ser in enumerate(SER_VALUES):
    n_rep = 1 if ser == 0 else N_REPEATS
    for rep in range(n_rep):
        rng = np.random.default_rng(seed=rep * 100 + ser_idx)
        # SER 적용: 전체 X를 오염시킨 후 assemble_split이 trial별로 슬라이싱
        X_c = apply_SER(X, ser, rng=rng) if ser > 0 else None

        rx_l, ry_l, _ = run_ridge_cv(X_corrupted=X_c)
        r_ser = (np.mean(rx_l) + np.mean(ry_l)) / 2
        results_ser[ser].append(r_ser)
        print(f"  SER={ser:.0e}  rep={rep+1}/{n_rep}  r={r_ser:.4f}")

r_neural_base = float(np.mean(results_ser[0]))
ser_arr       = np.array(SER_VALUES)
ratio_mean    = np.array([np.mean(results_ser[s]) / r_neural_base for s in SER_VALUES])
ratio_std     = np.array([np.std(results_ser[s])  / r_neural_base for s in SER_VALUES])

print(f"\nr_neural (SER=0, affine-rescaled): {r_neural_base:.4f}")
print(f"\n{'SER':>10}  {'ρ':>8}  {'std':>8}")
for i, ser in enumerate(SER_VALUES):
    print(f"  {ser:>8.0e}  {ratio_mean[i]:>8.4f}  {ratio_std[i]:>8.4f}")

# ─────────────────────────────────────────────────────────────
# PHASE 4: Noise Dilution Quantification (Mechanistic)
# ─────────────────────────────────────────────────────────────
print("\n" + "=" * 60)
print("PHASE 4: Noise Dilution Factor Analysis")
print("=" * 60)

N_neurons   = X.shape[1]                          # 161
mean_active = (X > 0).sum(axis=1).mean()          # active neurons per bin
feature_dim = NUM_LAGS * N_neurons                 # 3220

print(f"Total neurons N:          {N_neurons}")
print(f"Mean active per bin:      {mean_active:.1f}")
print(f"Feature vector dim:       {feature_dim}")

for ser in [1e-4, 1e-3, 1e-2, 1e-1]:
    # expected corrupted features per sample
    expected_active_features  = mean_active * NUM_LAGS
    expected_corrupted        = expected_active_features * (ser / 2) * 2  # miss + FA
    dilution_factor           = N_neurons / mean_active                    # ≈ 161/10 = 16
    print(f"\nSER={ser:.0e}:")
    print(f"  Expected corrupted features/sample: {expected_corrupted:.1f} / {feature_dim:.0f}")
    print(f"  Noise fraction:                     {expected_corrupted/feature_dim*100:.3f}%")
    print(f"  Dilution factor (N/active):         {dilution_factor:.1f}×")

# ─────────────────────────────────────────────────────────────
# PHASE 5: 시각화 (개선된 4개 그림)
# ─────────────────────────────────────────────────────────────
print("\n" + "=" * 60)
print("PHASE 5: 시각화")
print("=" * 60)

# ────────────────────────────────
# 그림 A: Baseline Performance
# ────────────────────────────────
fig1, axes1 = plt.subplots(1, 2, figsize=(12, 5))

decoders = ['Ridge\n(0.870)', 'MLP\n(0.921)', 'LSTM\n(0.895)', 'Transformer\n(0.910)']
r_vals   = [0.870, 0.921, 0.895, 0.910]
vaf_vals = [0.740, 0.842, 0.789, 0.819]
colors   = ['steelblue', 'darkorange', 'seagreen', 'crimson']

ax = axes1[0]
bars = ax.bar(decoders, r_vals, color=colors, alpha=0.85, edgecolor='white', linewidth=0.8)
ax.axhline(PAPER_R_NEURAL, color='red', linestyle='--', linewidth=1.8, label=f'Paper SNN ({PAPER_R_NEURAL})', zorder=5)
for bar, val in zip(bars, r_vals):
    ax.text(bar.get_x() + bar.get_width()/2, val + 0.003, f'{val:.3f}',
            ha='center', va='bottom', fontsize=10, fontweight='bold')
ax.set_ylim([0.80, 1.00])
ax.set_ylabel('Pearson r', fontsize=12)
ax.set_title('Baseline r_neural (SER=0)\nTrial-level CV, Affine-rescaled', fontsize=11, fontweight='bold')
ax.legend(fontsize=10); ax.grid(True, alpha=0.3, axis='y')

ax = axes1[1]
bars = ax.bar(decoders, vaf_vals, color=colors, alpha=0.85, edgecolor='white', linewidth=0.8)
for bar, val in zip(bars, vaf_vals):
    ax.text(bar.get_x() + bar.get_width()/2, val + 0.003, f'{val:.3f}',
            ha='center', va='bottom', fontsize=10, fontweight='bold')
ax.set_ylim([0.65, 0.90])
ax.set_ylabel('VAF (Variance Accounted For)', fontsize=12)
ax.set_title('VAF Comparison (SER=0)\nTrial-level CV', fontsize=11, fontweight='bold')
ax.grid(True, alpha=0.3, axis='y')

plt.suptitle('Phase 2: Baseline Decoding Performance\npmd-1 Dataset (MM_S1_processed)', fontsize=13, fontweight='bold')
plt.tight_layout()
plt.savefig('fig1_baseline_improved.png', dpi=150, bbox_inches='tight')
print("Saved: fig1_baseline_improved.png")

# ─────────────────────────────────────────────────────────────────────
# 그림 B: Extended SER Robustness + Subsampling (두 패널 합쳐서 핵심 그림)
# ─────────────────────────────────────────────────────────────────────
fig2, axes2 = plt.subplots(1, 2, figsize=(16, 6))

# B-Left: Extended SER 커브 (Rate-coded vs SNN)
ax = axes2[0]

# 재현 결과
ser_nonzero  = [s for s in SER_VALUES if s > 0]
ratio_nz_m   = ratio_mean[1:]
ratio_nz_s   = ratio_std[1:]

ax.semilogx(ser_nonzero, ratio_nz_m, 'b-o', linewidth=2.5, markersize=8,
            label=f'Ridge (r={r_neural_base:.3f})', zorder=5)
ax.fill_between(ser_nonzero,
                ratio_nz_m - ratio_nz_s,
                ratio_nz_m + ratio_nz_s,
                color='blue', alpha=0.12)

# 논문 기준 (SNN, 3점)
paper_ser    = [1e-4, 1e-3, 1e-2]
paper_ratios = [1.000, 0.888, 0.700]
# SER > 1e-2 는 SNN 데이터 없으므로 논문 커브는 1e-2까지만 표시
ax.semilogx(paper_ser, paper_ratios, 'r--s', linewidth=2, markersize=9,
            label='Nurmikko et al. 2024 (SNN)', zorder=4)
ax.fill_between(paper_ser,
                np.array(paper_ratios) - 0.05,
                np.array(paper_ratios) + 0.05,
                color='red', alpha=0.1, label='±0.05 tolerance')

ax.axvline(1e-2, color='gray', linestyle=':', alpha=0.6, linewidth=1.5)
ax.annotate('Breakdown\nregion →', xy=(1e-2, 0.75),
            fontsize=9, color='gray', ha='center')

ax.set_xlabel('SER (Spike Error Rate)', fontsize=12)
ax.set_ylabel('r_SER / r_neural  (Retention Ratio)', fontsize=12)
ax.set_title('Extended SER vs Decoding Performance\n'
             'Rate-coded (Ridge) vs SNN (Nurmikko 2024)', fontsize=11, fontweight='bold')
ax.set_ylim([0.50, 1.10])
ax.legend(fontsize=10, loc='lower left')
ax.grid(True, which='both', alpha=0.3)

# B-Right: Neuron Subsampling → Population Averaging 메커니즘
ax = axes2[1]
n_vals = list(N_SUBSET_VALUES)
m_vals = [sub_mean[n] for n in n_vals]
s_vals = [sub_std[n]  for n in n_vals]

ax.errorbar(n_vals, m_vals, yerr=s_vals,
            fmt='go-', linewidth=2.5, markersize=9,
            capsize=5, label=f'SER={SER_FIXED:.0e}', zorder=5)
ax.axhline(1.0, color='gray', linestyle='--', linewidth=1.2, alpha=0.7, label='Perfect retention')

# 이론 dilution curve: 단순 근사 1 - SER * (N_total/n)^(-1)
n_theory = np.linspace(10, 170, 100)
mean_sparsity_per_neuron = mean_active / N_neurons  # 평균 활성 비율
theory = 1.0 - SER_FIXED * (mean_active / n_theory)  # 단순 선형 근사
ax.plot(n_theory, np.clip(theory, 0.9, 1.0), 'g--', linewidth=1.5,
        alpha=0.5, label='Theory (linear approx.)')

ax.set_xlabel('Number of Neurons (N)', fontsize=12)
ax.set_ylabel('r_SER / r_neural  (Retention Ratio)', fontsize=12)
ax.set_title(f'Population Averaging Effect\n'
             f'N↑ → SER Robustness↑  (SER={SER_FIXED:.0e})', fontsize=11, fontweight='bold')
ax.set_xlim([0, 180])
ax.set_ylim([0.85, 1.05])
ax.legend(fontsize=10)
ax.grid(True, alpha=0.3)

# dilution factor 표시 (N=40, 161 두 점만)
offsets = {40: (-30, -0.012), 161: (5, -0.008)}  # (dx, dy) per point
for n_val in N_SUBSET_VALUES:
    dx, dy = offsets.get(n_val, (5, -0.008))
    ax.annotate(f'N={n_val}\nρ={sub_mean[n_val]:.3f}',
                xy=(n_val, sub_mean[n_val]),
                xytext=(n_val + dx, sub_mean[n_val] + dy),
                fontsize=9, color='darkgreen', fontweight='bold')

plt.suptitle('SER Robustness Analysis: Extended Sweep + Mechanistic Explanation',
             fontsize=13, fontweight='bold')
plt.tight_layout()
plt.savefig('fig2_ser_extended.png', dpi=150, bbox_inches='tight')
